expansion.raw:
lex: useEffect, cleanup, cleanup function, effect cleanup, component unmount, cleanup callback  
vec: A function that runs when a component unmounts to clean up subscriptions, timers, or event listeners  
hyde: useEffect(() => { const timer = setInterval(() => console.log('tick'), 1000); return () => clearInterval(timer); }, []);

lex: handleSubmit, handle submit, form submit, onsubmit, submit handler, form handling  
vec: A function triggered when a form is submitted, typically responsible for collecting and processing form data  
hyde: const handleSubmit = (event) => { event.preventDefault(); console.log('Form submitted'); };

lex: build combined index, merge indices, composite index, unified indexing, index fusion  
vec: Create a single index by combining multiple existing indexes into one cohesive structure  
hyde: def build_combined_index(indexes): return {k: v for idx in indexes for k, v in idx.items()}

lex: aggregate, retrieve, combine, merge, summarize, group, collect, consolidate, fetch, result aggregation  
vec: Combine multiple retrieval outputs into a unified, coherent set of results with prioritization and deduplication  
hyde: def aggregate_retrieval_results(results): return {k: v for k, v in results.items() if k not in [k for k, v in results.items() if v is None]}

lex: TypeError, undefined property, null check, object access, dot notation, property access error  
vec: A JavaScript error occurring when trying to access a property of an object that doesn't exist or is undefined  
hyde: const user = data?.user; if (!user) throw new Error("User data is undefined");

lex: ECONNREFUSED, connection refused, localhost error, network timeout, socket error, DNS resolution, port not listening  
vec: A network connection is being refused when trying to connect to a service running on localhost  
hyde: try { const response = await fetch('http://localhost:3000/api/data'); } catch (err) { if (err.code === 'ECONNREFUSED') console.log('Service not running on localhost'); }

lex: cors, origin, allowed, headers, cross-origin, forbidden, access-control, origin policy, header restrictions  
vec: A web application is failing because the server is blocking requests from a specific origin due to missing or misconfigured CORS headers  
hyde: function handleCORS(request, response) { if (!request.headers.origin) return response.status(403).send('CORS origin not allowed'); response.header('Access-Control-Allow-Origin', request.headers.origin); }

lex: memory leak, heap overflow, JVM OutOfMemoryError, garbage collection failure, memory exhaustion  
vec: The system is unable to allocate more memory in the heap, causing a crash due to insufficient available resources  
hyde: try { System.gc(); } catch (Exception e) { throw new RuntimeException("Heap allocation failed"); }

lex: promise rejected, unhandled rejection, async error, unhandled promise rejection, async timeout, error handling, rejection callback  
vec: A JavaScript async operation failed silently due to an uncaught promise rejection that wasn't properly handled  
hyde: async function fetchData() { throw new Error('Network error'); } setTimeout(() => { console.error('Unhandled rejection'); }, 1000);

lex: auth middleware, authentication filter, security middleware, login guard, session management, token verification, access control  
vec: A software component that verifies user identity and grants access to protected resources before processing requests  
hyde: class AuthMiddleware { public void handle(Request request) { if (!verifyToken(request.token)) throw new UnauthorizedException(); } }

lex: rate limiting, token bucket, sliding window, burst limit, request throttling, API throttling, quota system, concurrency control  
vec: A system that restricts the number of requests a client can make within a given time frame to prevent abuse and ensure fair usage  
hyde: def rate_limit(requests, window=60): return { 'max': 100, 'window': window, 'method': 'sliding_window' }

lex: dependency injection, service container, inversion of control, DI container, service locator, dependency injection framework  
vec: A system that automatically provides dependencies to objects at runtime, enabling loose coupling and easier testing  
hyde: class Container { public function register($service, $factory) { $this->services[$service] = $factory; } public function get($service) { return $this->services[$service](); } }

lex: server-sent events, SSE, streaming response, real-time updates, event stream, bidirectional communication  
vec: A server that continuously pushes real-time updates to a client via a streaming connection using event-based data transmission  
hyde: def stream_events(): while True: yield {"data": "update", "event": "sync"}

lex: react context, redux, state management, global state, react hooks, useContext, useSelector, store, action, dispatch, reducer, state updates, performance, re-rendering, data flow  
vec: Compare the mechanisms and use cases of React Context for managing local component state versus Redux for handling global application state and complex data flows  
hyde: const [count, setCount] = useState(0); const [state, dispatch] = useReducer(reducer, initialState); const value = useContext(MyContext);

lex: next function, middleware chain, express middleware, next(), express app middleware, execution flow, request handling, middleware execution, Express.js, next() callback  
vec: A function that continues the execution of a middleware chain in Express.js after current middleware has processed the request  
hyde: const next = (req, res, nextFn) => { if (req.next) req.next(); else res.send('Chain continues'); };

lex: prisma, find many, where clause, query, orm, prisma find many, filter, database query, find multiple, conditions  
vec: Retrieve multiple records from a database using Prisma with specific filtering criteria  
hyde: const users = await prisma.user.findMany({ where: { age: { gt: 25 } } });

lex: Next.js, server component, data fetching, fetch, getServerSideProps, SSR, server-side rendering, API route, fetch data, server action  
vec: A method to retrieve and display data on the server side within a Next.js component without requiring client-side hydration  
hyde: const fetchData = async () => { const res = await fetch('/api/data'); return res.json(); };

lex: zod, schema, validation, parse, transform, parse transform, schema validation, zod parse, zod transform  
vec: A function that takes a JSON object and validates its structure using Zod, then converts it into a typed JavaScript object with proper error handling  
hyde: const result = zodSchema.parse(inputData); if (result.success) return result.data; else throw new Error(result.error.message);

lex: tRPC, router, procedure, mutation, update, action, handler, endpoint, function, API, server, mutation, request, operation  
vec: A function that defines a server-side operation to update data, triggered by a client request and executed on the server side  
hyde: const mutation = async (input: { id: string, data: any }) => { return await updateRecord(input.id, input.data); };

lex: tailwind, responsive, breakpoints, utility classes, responsive design, Tailwind CSS, breakpoints utilities, mobile, tablet, desktop, screen sizes  
vec: A set of CSS utility classes that adjust styling based on screen size, such as mobile, tablet, and desktop views  
hyde: const breakpoints = ['sm', 'md', 'lg', 'xl']; return `@media (min-width: 640px) { ${breakpoints.map(b => `.${b} { padding: 1rem; }`)} }`;

lex: jest, mock, spyOn, testing, module, mock module, spyOn function, jest spy, unit testing, test mocking  
vec: How to effectively use Jest's spyOn to mock a module's functions during unit testing for better control over dependencies  
hyde: const mockModule = jest.spyOn(require('some-module'), 'someFunction').mockReturnValue('mocked'); jest.spyOn(mockModule, 'anotherFunc').mockImplementation(() => 'test');

lex: GitHub Actions, CI workflow, matrix strategy, workflow matrix, CI/CD, parallel testing, environment matrix, platform testing, build matrix  
vec: A configuration that runs the same workflow across multiple operating systems, programming languages, or environments to ensure compatibility and stability  
